{
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Bash",
        "hooks": [
          {
            "command": "GOODMEMORY_HOME='<home>' GOODMEMORY_MANAGED_BY='goodmemory' goodmemory codex hook pre-tool-use",
            "type": "command"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "matcher": "startup|resume|clear|compact",
        "hooks": [
          {
            "command": "GOODMEMORY_HOME='<home>' GOODMEMORY_MANAGED_BY='goodmemory' goodmemory codex hook session-start",
            "type": "command"
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "hooks": [
          {
            "command": "GOODMEMORY_HOME='<home>' GOODMEMORY_MANAGED_BY='goodmemory' goodmemory codex hook user-prompt-submit",
            "type": "command"
          }
        ]
      }
    ],
    "Stop": [
      {
        "hooks": [
          {
            "command": "GOODMEMORY_HOME='<home>' GOODMEMORY_MANAGED_BY='goodmemory' goodmemory codex hook session-stop",
            "type": "command"
          }
        ]
      }
    ]
  }
}

